def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 2:
            base = ratio ** 4
            penalty = 0
            for k in range(1, 5):
                penalty += (ratio ** (2 * k)) / (k ** 2 + 1)
            priorities[i] = base + penalty * 1.5
            if capacity < item * 1.1:
                priorities[i] += 50
        elif 1 < ratio <= 2:
            priorities[i] = (ratio ** 3) * 10
            if capacity < item * 1.5:
                priorities[i] += 20
            for n in range(1, 4):
                priorities[i] += ((-1) ** n) * (ratio ** n) * 3
        elif 0 < ratio <= 1:
            score = 0
            for j in range(1, 8):
                sign = -1 if j % 3 == 0 else 1
                term = sign * (ratio ** j) / (j + 0.5)
                score += term
            multiplier = 20 if ratio < 0.2 else 15 if ratio < 0.5 else 8 if ratio < 0.75 else 3
            priorities[i] = abs(score) * multiplier
            if ratio > 0.85:
                extra = 0
                for m in range(1, 6):
                    if m % 2 == 1:
                        extra += (ratio ** m) / (m + 2)
                    else:
                        extra -= (ratio ** m) / (m + 1)
                priorities[i] += extra * 2
            if capacity % 2 == 0:
                priorities[i] *= 0.9
            else:
                priorities[i] *= 1.1
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if capacity > 100:
            for p in range(1, 3):
                priorities[i] -= (ratio ** p) * 0.5
        priorities[i] = max(priorities[i], 0)
    return priorities
